- 'Top-selling vehicle' refers to the vehicle with the highest total sales;
- 'Second best-selling vehicle' refers to the vehicle with the second-highest total sales;
- 'Other vehicles' includes all vehicles that are not the top or second best-selling.

sql:
SELECT COUNT(vehicle_id) AS total_vehicles
FROM vehicles
WHERE price > (SELECT AVG(price) FROM vehicles);

